<?php    if ($_SERVER["REQUEST_METHOD"] == "POST") {        $name = $_POST["name"];        $company = $_POST["company"];        $email = $_POST["email"];        $phone = $_POST["phone"];        $message = $_POST["message"];        $captcha = $_POST["g-recaptcha-response"];        // Replace YOUR_SECRET_KEY with your actual reCAPTCHA secret key        $url = 'https://www.google.com/recaptcha/api/siteverify';        $data = array(            'secret' => '6LfYoIknAAAAAIALNPqlgHUZrdgkcRiKILiToxkB',            'response' => $captcha        );        $options = array(            'http' => array(                'header' => "Content-type: application/x-www-form-urlencoded\r\n",                'method' => 'POST',                'content' => http_build_query($data),            ),        );        $context = stream_context_create($options);        $response = file_get_contents($url, false, $context);        $result = json_decode($response, true);        if ($result['success']) {            // Process the form data here (e.g., send an email, save to a database, etc.)            // Replace the placeholders with your actual email and other processing code.            $to = "contactus@ibexwebtech.com";            $subject = "Inquiry from Website";			$message = "Name: $name\nCompany: $company\nEmail: $email\nPhone: $phone\nMessage: $message";            mail($to, $subject, $message);            echo "<script type='text/javascript'>alert('Your email was sent!')</script>";			echo "<script>document.location='contact-us.html'</script>";        } else {            echo "<p>CAPTCHA verification failed. Please try again.</p>";        }    }    ?>